#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t a,b,c; scanf("%" PRId64 " %" PRId64 " %" PRId64, &a,&b,&c);
        int64_t m = a;
        if(b>m) m=b;
        if(c>m) m=c;
        printf("%" PRId64 "\n", m+1);
    }
    return 0;
}

